mapper.select:
SELECT campus_id AS campusId, campus_name AS campusName, campus_code AS campusCode, sort_order AS sortOrder, create_time AS createTime, update_time AS updateTime FROM sys_campus WHERE is_deleted = 0
AND (campus_name LIKE CONCAT('%', #{keyword}, '%') OR campus_code LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY sort_order ASC, campus_id ASC LIMIT #{offset}, #{limit}
